248→export const uploadJournalContentService = async(
249→    content,
250→    title,
251→    userId,
252→    postType = POST_TYPE_TEXT,
253→    canvasDocInput = null,
254→    remixSourceJournalId = null,
255→    isRemix = false
256→) =>{
257→    if(!userId){
258→        console.error('userId is undefined');
259→        throw {status: 400, error: 'userId is undefined'};
260→    }
261→
262→    const resolvedPostType = normalizePostType(postType);
263→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
264→
265→    if(!trimmedTitle){
266→        console.error('title is missing!');
267→        throw {status: 400, error: 'title is missing!'};
268→    }
269→
270→    let embeddingBody = '';
271→    const shouldSaveRemixMetadata = Boolean(
272→        remixSourceJournalId
273→        && typeof remixSourceJournalId === 'string'
274→        && remixSourceJournalId.trim()
275→    );
276→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
277→    let payload = {
278→        user_id: userId,
279→        title: trimmedTitle,
280→        post_type: resolvedPostType
281→    };
282→
283→    if(resolvedPostType === POST_TYPE_CANVAS){
284→        let parsedCanvasDoc = null;
285→        try {
286→            parsedCanvasDoc = parseCanvasDocInput(canvasDocInput);
287→        } catch (error) {
288→            console.error('invalid canvas doc on insert:', error?.message || error);
289→            throw {status: 400, error: 'invalid canvas_doc'};
290→        }
291→
292→        if(!parsedCanvasDoc){
293→            console.error('canvas_doc is missing for canvas post');
294→            throw {status: 400, error: 'canvas_doc is missing'};
295→        }
296→
297→        embeddingBody = extractCanvasPlainText(parsedCanvasDoc);
298→        payload = {
299→            ...payload,
300→            content: null,
301→            canvas_doc: parsedCanvasDoc
302→        };
303→    } else {
304→        if(!content){
305→            console.error('content is missing for text post!');
306→            throw {status: 400, error: 'content is missing for text post'};
307→        }
308→
309→        const parseData = parseTextContentSafely(content);
310→        if(!parseData){
311→            console.error('error while parsing text content data');
312→            throw {status: 400, error: 'error while parsing text content data'};
313→        }
314→
315→        embeddingBody = parseData.wholeText || '';
316→        payload = {
317→            ...payload,
318→            content: content,
319→            canvas_doc: null
320→        };
321→    }
322→
323→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
324→
325→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
326→        console.error('error while generating embeddings on a post!');
327→        throw {status: 400, error: 'error while generating embeddings on a post!'};
328→    }
329→
330→    const insertPayload = {
331→        ...payload,
332→        embeddings: embeddingResult
333→    };
334→
335→    if(normalizedIsRemix){
336→        insertPayload.is_remix = true;
337→    }
338→    if(shouldSaveRemixMetadata){
339→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
340→    }
341→
342→    try {
343→        const {count: postCount} = await supabase
344→            .from('journals')
345→            .select('id', {count: 'exact', head: true})
346→            .eq('user_id', userId);
347→        const home = userHomeCoords(userId);
348→        const offset = spiralLayout(postCount || 0);
349→        insertPayload.universe_x = home.x + offset.dx;
350→        insertPayload.universe_y = home.y + offset.dy;
351→    } catch (coordErr) {
352→        console.error('non-fatal: failed to compute universe coords:', coordErr?.message || coordErr);
353→    }
354→
355→    let {error} = await supabase
356→    .from('journals')
357→    .insert(insertPayload);
358→
359→    if(error){
360→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
361→        if(missingRemixColumns){
362→            const fallbackPayload = {
363→                ...payload,
364→                embeddings: embeddingResult
365→            };
366→
367→            const retry = await supabase
368→            .from('journals')
369→            .insert(fallbackPayload);
370→            error = retry.error;
371→        }
372→    }
373→
374→    if(error){
375→        console.error('supabase error while uploading content:',error.message);
376→        throw {status: 500, error: 'supabase error while uploading content'};
377→    }
378→
379→    // Non-fatal: incrementally update galaxy positions for this user
380→    try {
381→        incrementalSettleForUser(userId).catch(err =>
382→            console.error('non-fatal: incremental settle failed:', err?.message || err)
383→        );
384→    } catch (settleErr) {
385→        console.error('non-fatal: incremental settle failed:', settleErr?.message || settleErr);
386→    }
387→
388→    return true;
389→}
