                    <div style={{display: 'flex', gap: '8px'}}>
                        <button
                            onClick={handleCloseCaptionEditor}
                            style={{
                                padding: '8px 16px', borderRadius: '8px', border: '1px solid var(--border-color, #ddd)',
                                background: 'transparent', cursor: 'pointer', fontSize: '13px',
