250→                                                <span className="so-handle">{handle}</span>
251→                                            )}
252→                                        </div>
253→                                    </div>
254→                                    <div className="so-date-row">
255→                                        <span className="ov-dot">·</span>
256→                                        <span className="ov-date">{formatPostDate(opinion.created_at)}</span>
257→                                    </div>
258→                                </div>
259→                                <div className="so-body" onClick={(e) => handleClickContent(e, opinion.id, opinion.user_id)}>
260→                                    {opinion.opinion}
261→                                </div>
262→                                <div className="so-meta-bar">
263→                                    <span className="so-reply-pill" onClick={(e) => { e.stopPropagation(); if(!session) return openAuthModal(); navigate('/home/opinionsViewer', { state: { opinionId: opinion.id, userId: opinion.user_id } }); }}>
264→                                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
265→                                            <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
266→                                        </svg>
267→                                        Reply
268→                                    </span>
269→                                </div>
270→                            </div>
271→                        </div>
272→                    </div>
273→                )
274→            })}
275→            <div className="opinions-in-view" ref={ref}>
276→            </div>
277→        </div>
278→
279→            
280→        </>
281→        </AnimatePresence>
282→    )
283→}
284→
285→export default OpinionsPage;
